// ─── SRD 5.2.1 Bestiary Import ───────────────────────────────────
// Regenerates src/data/monsters-*.ts from the 5etools 2024 Monster Manual
// data, filtered to entries flagged srd52 (System Reference Document 5.2.1,
// CC-BY-4.0 — the legally redistributable subset).
//
//   npm run import:bestiary            # fetch from the pinned commit
//   npm run import:bestiary -- --local path/to/bestiary-xmm.json
//
// The pinned SHA makes regeneration reproducible; generated files are
// committed, so builds never need the network. The audit gate at the end
// fails loudly on converter drift instead of shipping garbage stat blocks.

import { readFileSync, writeFileSync } from 'node:fs';
import { join } from 'node:path';
import { import5eToolsBestiary } from '../src/lib/import-5etools';
import type { FiveEToolsMonster, Monster } from '../src/lib/types';

const SOURCE_SHA = '974d5bfb7ceae1a13c0213d9b73d9692bd28ca49'; // 5etools-src v2.32.0
const SOURCE_URL = `https://raw.githubusercontent.com/5etools-mirror-3/5etools-src/${SOURCE_SHA}/data/bestiary/bestiary-xmm.json`;
const DATA_DIR = join(__dirname, '..', 'src', 'data');

const FILE_HEADER = `// AUTO-GENERATED by scripts/import-bestiary.ts — DO NOT EDIT BY HAND.
// Source: 5etools-src @ ${SOURCE_SHA.slice(0, 12)} (bestiary-xmm.json),
// filtered to entries in the System Reference Document 5.2.1.
// SRD 5.2.1 content © Wizards of the Coast LLC, licensed under the
// Creative Commons Attribution 4.0 International License (CC-BY-4.0):
// https://creativecommons.org/licenses/by/4.0/legalcode
`;

interface Band {
  file: string;
  exportName: string;
  label: string;
  maxCr: number;
}

const BANDS: Band[] = [
  { file: 'monsters-cr0-quarter.ts', exportName: 'MONSTERS_CR_0_QUARTER', label: 'CR 0 – 1/4', maxCr: 0.25 },
  { file: 'monsters-cr-half-1.ts', exportName: 'MONSTERS_CR_HALF_1', label: 'CR 1/2 – 1', maxCr: 1 },
  { file: 'monsters-cr2-4.ts', exportName: 'MONSTERS_CR_2_4', label: 'CR 2 – 4', maxCr: 4 },
  { file: 'monsters-cr5-8.ts', exportName: 'MONSTERS_CR_5_8', label: 'CR 5 – 8', maxCr: 8 },
  { file: 'monsters-cr9-13.ts', exportName: 'MONSTERS_CR_9_13', label: 'CR 9 – 13', maxCr: 13 },
  { file: 'monsters-cr14-20.ts', exportName: 'MONSTERS_CR_14_20', label: 'CR 14 – 20', maxCr: 20 },
  { file: 'monsters-cr21-30.ts', exportName: 'MONSTERS_CR_21_30', label: 'CR 21 – 30', maxCr: 30 },
];

async function obtainBestiary(): Promise<{ monster: FiveEToolsMonster[] }> {
  const localFlag = process.argv.indexOf('--local');
  if (localFlag !== -1) {
    const path = process.argv[localFlag + 1];
    if (!path) throw new Error('--local requires a file path');
    console.log(`Reading local file: ${path}`);
    return JSON.parse(readFileSync(path, 'utf-8'));
  }
  console.log(`Fetching ${SOURCE_URL}`);
  const res = await fetch(SOURCE_URL);
  if (!res.ok) {
    throw new Error(
      `Fetch failed (${res.status}). If the mirror moved, download the file manually and use --local.`,
    );
  }
  return (await res.json()) as { monster: FiveEToolsMonster[] };
}

interface AuditFailure {
  monster: string;
  problem: string;
}

function audit(monsters: Monster[], rawByName: Map<string, FiveEToolsMonster>): AuditFailure[] {
  const failures: AuditFailure[] = [];

  // Uniqueness
  const seenIds = new Set<string>();
  const seenNames = new Set<string>();
  for (const m of monsters) {
    if (seenIds.has(m.id)) failures.push({ monster: m.name, problem: `duplicate id ${m.id}` });
    if (seenNames.has(m.name)) failures.push({ monster: m.name, problem: 'duplicate name' });
    seenIds.add(m.id);
    seenNames.add(m.name);
  }

  // Per-monster integrity
  for (const m of monsters) {
    const serialized = JSON.stringify(m);
    if (serialized.includes('{@')) {
      const residue = serialized.match(/\{@\w+[^}]*\}/g)?.slice(0, 3).join(' ');
      failures.push({ monster: m.name, problem: `unstripped tag(s): ${residue}` });
    }
    if (serialized.includes('[object Object]')) {
      failures.push({ monster: m.name, problem: 'unflattened entry ([object Object])' });
    }
    // Only a failure when the source HAD actions and we lost them —
    // a few creatures (e.g. Shrieker Fungus) genuinely have none.
    const rawActions = rawByName.get(m.name)?.action;
    if (m.actions.length === 0 && Array.isArray(rawActions) && rawActions.length > 0) {
      failures.push({ monster: m.name, problem: 'raw actions existed but none parsed' });
    }
    if (m.movementModes.length === 0) {
      failures.push({ monster: m.name, problem: 'no movement modes' });
    }
    if (m.xp === 0 && m.challengeRating > 0) {
      failures.push({ monster: m.name, problem: `xp=0 at CR ${m.challengeRating}` });
    }
    if (m.hitPoints <= 0) {
      failures.push({ monster: m.name, problem: `hitPoints=${m.hitPoints}` });
    }
  }

  // Attack-bonus coverage: every raw action written in {@atkr} notation
  // should have produced a parsed attackBonus. Tolerate 5% for oddballs.
  let atkrActions = 0;
  let atkrWithBonus = 0;
  for (const m of monsters) {
    const raw = rawByName.get(m.name);
    if (!raw?.action) continue;
    for (const rawAction of raw.action) {
      const text = JSON.stringify(rawAction.entries ?? '');
      if (!text.includes('{@atkr')) continue;
      atkrActions++;
      const parsed = m.actions.find((a) => a.name === String(rawAction.name ?? ''));
      if (parsed?.attackBonus !== undefined) atkrWithBonus++;
    }
  }
  const coverage = atkrActions === 0 ? 1 : atkrWithBonus / atkrActions;
  console.log(`Attack-bonus coverage: ${atkrWithBonus}/${atkrActions} (${(coverage * 100).toFixed(1)}%)`);
  if (coverage < 0.95) {
    failures.push({ monster: '(aggregate)', problem: `attack-bonus coverage ${(coverage * 100).toFixed(1)}% < 95%` });
  }

  return failures;
}

function emitBandFile(band: Band, monsters: Monster[]): void {
  const body = JSON.stringify(monsters, null, 2);
  const content = `${FILE_HEADER}
import { Monster } from '../lib/types';

// ${band.label} — ${monsters.length} monsters
export const ${band.exportName}: Monster[] = ${body};
`;
  writeFileSync(join(DATA_DIR, band.file), content, 'utf-8');
  console.log(`  ${band.file}: ${monsters.length} monsters (${band.label})`);
}

async function main(): Promise<void> {
  const data = await obtainBestiary();
  console.log(`Total monsters in source: ${data.monster.length}`);

  const srdEntries = data.monster.filter(
    (m) => m.srd52 === true || typeof m.srd52 === 'string',
  );
  console.log(`SRD 5.2.1 entries: ${srdEntries.length}`);

  const copyUsers = srdEntries.filter((m) => '_copy' in m && m._copy !== undefined);
  if (copyUsers.length > 0) {
    throw new Error(
      `_copy inheritance is not supported; offending entries: ${copyUsers.map((m) => m.name).join(', ')}`,
    );
  }

  const converted = import5eToolsBestiary({ monster: srdEntries }, { forceSource: 'SRD52' });
  converted.sort((a, b) => a.challengeRating - b.challengeRating || a.name.localeCompare(b.name));

  const rawByName = new Map(
    srdEntries.map((m) => [typeof m.srd52 === 'string' ? m.srd52 : m.name, m]),
  );
  const failures = audit(converted, rawByName);
  if (failures.length > 0) {
    console.error(`\nAUDIT FAILED — ${failures.length} problem(s):`);
    for (const f of failures.slice(0, 25)) {
      console.error(`  ${f.monster}: ${f.problem}`);
    }
    if (failures.length > 25) console.error(`  ...and ${failures.length - 25} more`);
    process.exit(1);
  }
  console.log('Audit passed.');

  console.log('\nWriting data files:');
  let previousMax = -1;
  for (const band of BANDS) {
    const bandMonsters = converted.filter(
      (m) => m.challengeRating > previousMax && m.challengeRating <= band.maxCr,
    );
    emitBandFile(band, bandMonsters);
    previousMax = band.maxCr;
  }

  const meta = `${FILE_HEADER}
export const BESTIARY_META = {
  count: ${converted.length},
  source: 'SRD 5.2.1',
  license: 'CC-BY-4.0',
  sourceCommit: '${SOURCE_SHA}',
} as const;
`;
  writeFileSync(join(DATA_DIR, 'bestiary-meta.ts'), meta, 'utf-8');
  console.log(`  bestiary-meta.ts: count=${converted.length}`);

  // CR coverage report
  const byCr = new Map<number, number>();
  for (const m of converted) byCr.set(m.challengeRating, (byCr.get(m.challengeRating) ?? 0) + 1);
  const crs = Array.from(byCr.keys()).sort((a, b) => a - b);
  console.log(`\nCR coverage: ${crs.map((cr) => `${cr}×${byCr.get(cr)}`).join(', ')}`);
  console.log(`\nDone — ${converted.length} SRD 5.2.1 monsters imported.`);
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
